const items = $input.all();
const dashboard = items[0]?.json || {};
const weekly = items[1]?.json || {};
const stats = dashboard.stats || dashboard || {};
const now = new Date();
const date = now.toLocaleDateString('en-IN', {day:'numeric',month:'long',year:'numeric',timeZone:'Asia/Kolkata'});

let report = '📋 WB Grievance Portal — Daily Report\n📅 ' + date + '\n\n';
report += '📊 সারসংক্ষেপ | Summary:\n';
report += '├ 📥 নতুন অভিযোগ: ' + (stats.newToday||stats.total||0) + '\n';
report += '├ ✅ সমাধান: ' + (stats.resolved||0) + '\n';
report += '├ 🔄 চলমান: ' + (stats.inProgress||0) + '\n';
report += '├ 📤 খোলা: ' + (stats.open||0) + '\n';
report += '├ ❌ বাতিল: ' + (stats.rejected||0) + '\n';
report += '└ ⚠️ SLA লঙ্ঘন: ' + (stats.breached||0) + '\n\n';

if (stats.byUrgency) {
  report += '🔴 জরুরিতা অনুযায়ী | By Urgency:\n';
  Object.entries(stats.byUrgency).forEach(([k,v]) => report += '├ ' + k + ': ' + v + '\n');
  report += '\n';
}
if (stats.byCategory) {
  report += '📂 বিভাগ অনুযায়ী | By Category:\n';
  const cats = Object.entries(stats.byCategory).sort((a,b) => b[1]-a[1]);
  cats.slice(0,5).forEach(([k,v]) => report += '├ ' + k + ': ' + v + '\n');
  if (cats.length > 5) report += '└ ... and ' + (cats.length-5) + ' more\n';
  report += '\n';
}
report += '⭐ গড় রেটিং: ' + (stats.avgRating || 'N/A') + '/5 (গত ৭ দিনে)';

return [{ json: { report } }];

const report = $('Format Daily Report').first().json.report;
const users = $input.first().json.users || [];
return users.filter(u => u.notifyVia !== 'none' && u.whatsappPhone).map(u => ({ json: { phone: u.whatsappPhone, report } }));
